// ImageBox.cs - Custom ImageBox Widget
using System;
using Microsoft.Xna.Framework;
using Microsoft.Xna.Framework.Graphics;
using Sexy;

public class ImageBox : Widget
{
    public int mX;
    public int mY;
    public int mWidth;
    public int mHeight;
    public Image mImage;
    public float mScaleX = 1.0f;
    public float mScaleY = 1.0f;
    public bool mStretch = false;

    public ImageBox()
    {
        mX = 0;
        mY = 0;
        mWidth = 100;
        mHeight = 100;
    }

    public override void Draw(Graphics g)
    {
        if (mImage != null)
        {
            if (mStretch)
            {
                float scaleX = (float)mWidth / mImage.mWidth;
                float scaleY = (float)mHeight / mImage.mHeight;
                g.DrawImageF(mImage, mX, mY, scaleX, scaleY);
            }
            else
            {
                g.DrawImageF(mImage, mX, mY, mScaleX, mScaleY);
            }
        }
    }
}
